import torch
import torch.nn as nn


class MovingAvg(nn.Module):
    def __init__(self, kernel_size: int, stride: int = 1):
        super().__init__()
        self.kernel_size = kernel_size
        self.avg = nn.AvgPool1d(kernel_size=kernel_size, stride=stride, padding=0)

    def forward(self, x):
        # x: [B, L, C]
        pad = (self.kernel_size - 1) // 2
        front = x[:, 0:1, :].repeat(1, pad, 1)
        end = x[:, -1:, :].repeat(1, pad, 1)
        x = torch.cat([front, x, end], dim=1)
        x = self.avg(x.transpose(1, 2)).transpose(1, 2)
        return x


class SeriesDecomp(nn.Module):
    def __init__(self, kernel_size: int):
        super().__init__()
        self.moving_avg = MovingAvg(kernel_size, stride=1)

    def forward(self, x):
        trend = self.moving_avg(x)
        seasonal = x - trend
        return seasonal, trend


class DLinearForecaster(nn.Module):
    def __init__(self, seq_len: int = 96, pred_len: int = 720, n_features: int = 7, individual: bool = True, kernel_size: int = 25):
        super().__init__()
        self.seq_len = seq_len
        self.pred_len = pred_len
        self.n_features = n_features
        self.individual = individual
        self.decomp = SeriesDecomp(kernel_size)

        if individual:
            self.linear_seasonal = nn.ModuleList([nn.Linear(seq_len, pred_len) for _ in range(n_features)])
            self.linear_trend = nn.ModuleList([nn.Linear(seq_len, pred_len) for _ in range(n_features)])
            for i in range(n_features):
                nn.init.constant_(self.linear_seasonal[i].weight, 1.0 / seq_len)
                nn.init.constant_(self.linear_trend[i].weight, 1.0 / seq_len)
        else:
            self.linear_seasonal = nn.Linear(seq_len, pred_len)
            self.linear_trend = nn.Linear(seq_len, pred_len)
            nn.init.constant_(self.linear_seasonal.weight, 1.0 / seq_len)
            nn.init.constant_(self.linear_trend.weight, 1.0 / seq_len)

    def forward(self, x):
        seasonal, trend = self.decomp(x)
        if self.individual:
            outs = []
            for i in range(self.n_features):
                s = self.linear_seasonal[i](seasonal[:, :, i])
                t = self.linear_trend[i](trend[:, :, i])
                outs.append((s + t).unsqueeze(-1))
            return torch.cat(outs, dim=-1)
        seasonal = self.linear_seasonal(seasonal.transpose(1, 2))
        trend = self.linear_trend(trend.transpose(1, 2))
        return (seasonal + trend).transpose(1, 2)
